import pypsa
import pandas as pd
import matplotlib.pyplot as plt

# ==========================================
# 1. Load the Solved Network
# ==========================================
# Target the 2-cluster solved file generated by Snakemake
network_path = "../results/networks/elec_s_2_ec_lcopt_Co2L.nc"
print(f"Loading network: {network_path}...")
n = pypsa.Network(network_path)

# ==========================================
# 2. Spatial Capacity Analysis (The "Where")
# ==========================================
print("\n--- Optimized Generator Capacities by Node (MW) ---")
# Pivot the dataframe to show Carriers (rows) vs Nodes (columns)
gen_caps = n.generators.groupby(['carrier', 'bus']).p_nom_opt.sum().unstack().fillna(0)
print(gen_caps.round(2))

print("\n--- Optimized Storage Capacities by Node (MW) ---")
if not n.storage_units.empty:
    storage_caps = n.storage_units.groupby(['carrier', 'bus']).p_nom_opt.sum().unstack().fillna(0)
    print(storage_caps.round(2))
else:
    print("No native StorageUnits built (PyPSA-Earth may use Stores/Links for batteries).")

# ==========================================
# 3. Temporal Dispatch Analysis (The "When")
# ==========================================
# Aggregate all generation across both nodes hour-by-hour
dispatch = n.generators_t.p.T.groupby(n.generators.carrier).sum().T

# Extract total national demand
demand = n.loads_t.p_set.sum(axis=1)

# Handle battery dynamics if they exist
if not n.storage_units.empty:
    dispatch['Battery_Discharging'] = n.storage_units_t.p.clip(lower=0).sum(axis=1)
    dispatch['Battery_Charging'] = n.storage_units_t.p.clip(upper=0).sum(axis=1)

# ==========================================
# 4. Visualization
# ==========================================
# Set up a 2-panel plot
fig, axes = plt.subplots(2, 1, figsize=(14, 12), gridspec_kw={'height_ratios': [2, 1]})

# --- Subplot 1: National Dispatch ---
# Filter out empty carriers so the plot doesn't crash
plot_data = dispatch.loc[:, (dispatch != 0).any(axis=0)]

# Plot stacked area (excluding charging, which is negative demand)
plot_data.drop(columns=["Battery_Charging"], errors="ignore").plot.area(
    ax=axes[0], colormap='tab20', alpha=0.8
)

# Overlay the demand line
axes[0].plot(demand.index, demand, color='black', linewidth=3, label='Total National Demand')
axes[0].set_title("System-Wide Hourly Dispatch (1 Week)", fontsize=14, fontweight='bold')
axes[0].set_ylabel("Power (MW)", fontsize=12)
axes[0].legend(loc='upper left', bbox_to_anchor=(1.02, 1))
axes[0].grid(linestyle='-', alpha=0.5)

# --- Subplot 2: Transmission Flows ---
# Analyze the power flow on the AC lines connecting the two nodes
if not n.links.empty:
    line_flows = n.links_t.p0
    line_flows.plot(ax=axes[1], alpha=0.8, linewidth=1.5)
    
    axes[1].set_title("Transmission Line Flows Between Nodes", fontsize=14, fontweight='bold')
    axes[1].set_ylabel("Power Flow (MW)", fontsize=12)
    axes[1].set_xlabel("Time", fontsize=12)
    
    # Add a horizontal line at 0 for reference
    axes[1].axhline(0, color='black', linestyle='--', linewidth=1)
    
    # A positive value usually means flow from Bus0 to Bus1, negative means Bus1 to Bus0
    axes[1].legend([f"Line: {col}" for col in line_flows.columns], loc='upper left', bbox_to_anchor=(1.02, 1))
    axes[1].grid(linestyle='--', alpha=0.5)

plt.tight_layout()
plt.show()